} from '../../../../src/newArch/store/rewardProgram/store';
import { PermissionStatus } from '../../../../src/newArch/store/rewardProgram/models';

describe('PermissionSlice', () => {
  let slice: PermissionSlice;
  let mockSet: jest.Mock;

  beforeEach(() => {
    mockSet = jest.fn();
    slice = createPermissionSlice(mockSet, jest.fn(), {} as any);
  });

  describe('initial state', () => {
    it('should have correct initial values', () => {
      expect(slice.rewardsPermission.status).toBe(PermissionStatus.IDLE);
      expect(slice.rewardsPermission.hasRedeemed).toBeNull();
    });
  });

  describe('actions', () => {
    describe('setStatus', () => {
      it('should set status to LOADING', () => {
        slice.rewardPermissionActions.setStatus(PermissionStatus.LOADING);

        expect(mockSet).toHaveBeenCalledWith(expect.any(Function));

        const updateFn = mockSet.mock.calls[0][0];
        const newState = updateFn({ rewardsPermission: slice.rewardsPermission });

        expect(newState.rewardsPermission.status).toBe(PermissionStatus.LOADING);
      });

      it('should set status to SUCCESS', () => {
        slice.rewardPermissionActions.setStatus(PermissionStatus.SUCCESS);

        expect(mockSet).toHaveBeenCalledWith(expect.any(Function));

        const updateFn = mockSet.mock.calls[0][0];
        const newState = updateFn({ rewardsPermission: slice.rewardsPermission });

        expect(newState.rewardsPermission.status).toBe(PermissionStatus.SUCCESS);
      });

      it('should set status to ERROR', () => {
        slice.rewardPermissionActions.setStatus(PermissionStatus.ERROR);

        expect(mockSet).toHaveBeenCalledWith(expect.any(Function));

        const updateFn = mockSet.mock.calls[0][0];
        const newState = updateFn({ rewardsPermission: slice.rewardsPermission });

        expect(newState.rewardsPermission.status).toBe(PermissionStatus.ERROR);
      });

      it('should preserve hasRedeemed when setting status', () => {
        const currentState = {
          rewardsPermission: {
            status: PermissionStatus.IDLE,
            hasRedeemed: true,
          },
        };

        slice.rewardPermissionActions.setStatus(PermissionStatus.LOADING);

        const updateFn = mockSet.mock.calls[0][0];
        const newState = updateFn(currentState);

        expect(newState.rewardsPermission.hasRedeemed).toBe(true);
        expect(newState.rewardsPermission.status).toBe(PermissionStatus.LOADING);
      });
    });

    describe('setHasRedeemed', () => {
      it('should set hasRedeemed to true and status to SUCCESS', () => {
        slice.rewardPermissionActions.setHasRedeemed(true);

        expect(mockSet).toHaveBeenCalledWith(expect.any(Function));

        const updateFn = mockSet.mock.calls[0][0];
        const newState = updateFn({ rewardsPermission: slice.rewardsPermission });

        expect(newState.rewardsPermission.hasRedeemed).toBe(true);
        expect(newState.rewardsPermission.status).toBe(PermissionStatus.SUCCESS);
      });

      it('should set hasRedeemed to false and status to SUCCESS', () => {
        slice.rewardPermissionActions.setHasRedeemed(false);

        expect(mockSet).toHaveBeenCalledWith(expect.any(Function));

        const updateFn = mockSet.mock.calls[0][0];
        const newState = updateFn({ rewardsPermission: slice.rewardsPermission });

        expect(newState.rewardsPermission.hasRedeemed).toBe(false);
        expect(newState.rewardsPermission.status).toBe(PermissionStatus.SUCCESS);
      });

      it('should automatically set status to SUCCESS when setting hasRedeemed', () => {
        const currentState = {
          rewardsPermission: {
            status: PermissionStatus.LOADING,
            hasRedeemed: null,
          },
        };

        slice.rewardPermissionActions.setHasRedeemed(true);

        const updateFn = mockSet.mock.calls[0][0];
        const newState = updateFn(currentState);

        expect(newState.rewardsPermission.status).toBe(PermissionStatus.SUCCESS);
      });
    });

    describe('reset', () => {
      it('should reset state to initial values', () => {
        slice.rewardPermissionActions.reset();

        expect(mockSet).toHaveBeenCalledWith({
          rewardsPermission: {
            status: PermissionStatus.IDLE,
            hasRedeemed: null,
          },
        });
      });
    });
  });

  describe('state isolation', () => {
    it('should not mutate previous state', () => {
      const previousState = {
        rewardsPermission: {
          status: PermissionStatus.IDLE,
          hasRedeemed: null,
        },
      };

      slice.rewardPermissionActions.setHasRedeemed(true);

      const updateFn = mockSet.mock.calls[0][0];
      const newState = updateFn(previousState);

      expect(previousState.rewardsPermission.hasRedeemed).toBeNull();
      expect(previousState.rewardsPermission.status).toBe(PermissionStatus.IDLE);
      expect(newState.rewardsPermission.hasRedeemed).toBe(true);
      expect(newState.rewardsPermission.status).toBe(PermissionStatus.SUCCESS);
    });
  });
});

