import {
  checkHasRedeemed,
  markAsRedeemed,
} from '../../../../src/newArch/store/rewardProgram/services';
import { getPermissionApi, savePermissionApi } from '../../../../src/newArch/store/rewardProgram/api';
import { mapPermissionResponse } from '../../../../src/newArch/store/rewardProgram/repository';
import { useRootStore } from '../../../../src/store';
import { PermissionStatus } from '../../../../src/newArch/store/rewardProgram/models';

jest.mock('../../../../src/newArch/store/rewardProgram/api');
jest.mock('../../../../src/newArch/store/rewardProgram/repository');
jest.mock('../../../../src/store', () => ({
  useRootStore: {
    getState: jest.fn(),
  },
}));

describe('Permission Service', () => {
  const mockSetStatus = jest.fn();
  const mockSetHasRedeemed = jest.fn();

  beforeEach(() => {
    jest.clearAllMocks();
    (useRootStore.getState as jest.Mock).mockReturnValue({
      rewardsPermission: {
        status: PermissionStatus.IDLE,
        hasRedeemed: null,
      },
      rewardPermissionActions: {
        setStatus: mockSetStatus,
        setHasRedeemed: mockSetHasRedeemed,
        reset: jest.fn(),
      },
    });
  });

  describe('checkHasRedeemed', () => {
    it('should return true when user has redeemed', async () => {
      const mockApiResponse = {
        status: 200,
        data: {
          data: {
            codigoCliente: '12345678',
            value: {
              invoiceCashbackRedemption: {
                redeemedAtDate: '2024-01-01T00:00:00.000Z',
              },
            },
            status: 1,
          },
        },
      };

      const mockMappedValue = {
        invoiceCashbackRedemption: {
          redeemedAtDate: '2024-01-01T00:00:00.000Z',
        },
      };

      (getPermissionApi as jest.Mock).mockResolvedValue(mockApiResponse);
      (mapPermissionResponse as jest.Mock).mockReturnValue(mockMappedValue);

      const result = await checkHasRedeemed('12345678');

      expect(mockSetStatus).toHaveBeenCalledWith(PermissionStatus.LOADING);
      expect(getPermissionApi).toHaveBeenCalledWith({ accountNumber: '12345678' });
      expect(mapPermissionResponse).toHaveBeenCalledWith(mockApiResponse.data);
      expect(mockSetHasRedeemed).toHaveBeenCalledWith(true);
      expect(result).toBe(true);
    });

    it('should return false when user has not redeemed', async () => {
      const mockApiResponse = {
        status: 200,
        data: {
          data: {
            codigoCliente: '12345678',
            value: {
              invoiceCashbackRedemption: {
                redeemedAtDate: undefined,
              },
            },
            status: 0,
          },
        },
      };

      const mockMappedValue = {
        invoiceCashbackRedemption: {
          redeemedAtDate: undefined,
        },
      };

      (getPermissionApi as jest.Mock).mockResolvedValue(mockApiResponse);
      (mapPermissionResponse as jest.Mock).mockReturnValue(mockMappedValue);

      const result = await checkHasRedeemed('12345678');

      expect(mockSetStatus).toHaveBeenCalledWith(PermissionStatus.LOADING);
      expect(mockSetHasRedeemed).toHaveBeenCalledWith(false);
      expect(result).toBe(false);
    });

    it('should return false when redeemedAtDate is missing', async () => {
      const mockApiResponse = {
        status: 200,
        data: {
          data: {
            codigoCliente: '12345678',
            value: {},
            status: 0,
          },
        },
      };

