  expect(mockSetStatus).toHaveBeenCalledWith(PermissionStatus.LOADING);
  expect(mockSetHasRedeemed).toHaveBeenCalledWith(true);
});
```

**`__tests__/services/permission/store/index.test.ts`** (152 lines)
- Tests Zustand slice creation and actions
- Tests setHasRedeemed automatically sets SUCCESS status
```typescript
