import { renderHook, act } from '@testing-library/react-native';
import { usePermission } from '../../../../src/newArch/store/rewardProgram/hooks';
import {
  checkHasRedeemed as checkHasRedeemedService,
  markAsRedeemed as markAsRedeemedService,
} from '../../../../src/newArch/store/rewardProgram/services';
import { getClientNRC } from '../../../../src/hooks/useSelectors';
import { PermissionStatus } from '../../../../src/newArch/store/rewardProgram/models';

const mockUseRootStore = jest.fn();
jest.mock('~/store', () => ({
  useRootStore: mockUseRootStore,
}));

jest.mock('../../../../src/newArch/store/rewardProgram/services', () => ({
  checkHasRedeemed: jest.fn(),
  markAsRedeemed: jest.fn(),
}));

jest.mock('../../../../src/hooks/useSelectors', () => ({
  getClientNRC: jest.fn(),
}));

describe('usePermission', () => {
  const mockAccountId = '12345678';

  beforeEach(() => {
    jest.clearAllMocks();
    (getClientNRC as jest.Mock).mockReturnValue(mockAccountId);
  });

  describe('initial state', () => {
    it('should return initial state from store', () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      const { result } = renderHook(() => usePermission());

      expect(result.current.hasRedeemed).toBeNull();
      expect(result.current.isLoading).toBe(false);
      expect(result.current.isError).toBe(false);
    });

    it('should return isLoading true when status is LOADING', () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.LOADING,
            },
          });
        }
      });

      const { result } = renderHook(() => usePermission());

      expect(result.current.isLoading).toBe(true);
      expect(result.current.isError).toBe(false);
    });

    it('should return isError true when status is ERROR', () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.ERROR,
            },
          });
        }
      });

      const { result } = renderHook(() => usePermission());

      expect(result.current.isError).toBe(true);
      expect(result.current.isLoading).toBe(false);
    });
  });

  describe('checkHasRedeemed', () => {
    it('should return cached value when hasRedeemed is not null', async () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: true,
              status: PermissionStatus.SUCCESS,
            },
          });
        }
      });

      const { result } = renderHook(() => usePermission());

      let checkResult: boolean = false;
      await act(async () => {
        checkResult = await result.current.checkHasRedeemed();
      });

      expect(checkResult).toBe(true);
      expect(checkHasRedeemedService).not.toHaveBeenCalled();
    });

    it('should call service when hasRedeemed is null', async () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      (checkHasRedeemedService as jest.Mock).mockResolvedValue(true);

      const { result } = renderHook(() => usePermission());

      let checkResult: boolean = false;
      await act(async () => {
        checkResult = await result.current.checkHasRedeemed();
      });

      expect(checkResult).toBe(true);
      expect(checkHasRedeemedService).toHaveBeenCalledWith(mockAccountId);
    });

    it('should call service when forceRefresh is true', async () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: false,
              status: PermissionStatus.SUCCESS,
            },
          });
        }
      });

      (checkHasRedeemedService as jest.Mock).mockResolvedValue(true);

      const { result } = renderHook(() => usePermission());

      let checkResult: boolean = false;
      await act(async () => {
        checkResult = await result.current.checkHasRedeemed({ forceRefresh: true });
      });

      expect(checkResult).toBe(true);
      expect(checkHasRedeemedService).toHaveBeenCalledWith(mockAccountId);
    });

    it('should throw error when accountId is not defined', async () => {
      (getClientNRC as jest.Mock).mockReturnValue(null);

      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      const { result } = renderHook(() => usePermission());

      await expect(async () => {
        await act(async () => {
          await result.current.checkHasRedeemed();
        });
      }).rejects.toThrow('Expected accountId to be defined.');
    });
  });

  describe('markAsRedeemed', () => {
    it('should call service with accountId', async () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      (markAsRedeemedService as jest.Mock).mockResolvedValue(true);

      const { result } = renderHook(() => usePermission());

      let markResult: boolean = false;
      await act(async () => {
        markResult = await result.current.markAsRedeemed();
      });

      expect(markResult).toBe(true);
      expect(markAsRedeemedService).toHaveBeenCalledWith(mockAccountId);
    });

    it('should return false when accountId is not defined', async () => {
      (getClientNRC as jest.Mock).mockReturnValue(null);

      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      const { result } = renderHook(() => usePermission());

      let markResult: boolean = true;
      await act(async () => {
        markResult = await result.current.markAsRedeemed();
      });

      expect(markResult).toBe(false);
      expect(markAsRedeemedService).not.toHaveBeenCalled();
    });

    it('should handle service errors gracefully', async () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      (markAsRedeemedService as jest.Mock).mockResolvedValue(false);

      const { result } = renderHook(() => usePermission());

      let markResult: boolean = true;
      await act(async () => {
        markResult = await result.current.markAsRedeemed();
      });

      expect(markResult).toBe(false);
    });
  });

  describe('function stability', () => {
    it('should maintain stable function references across rerenders', () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      const { result, rerender } = renderHook(() => usePermission());

      const initialCheckHasRedeemed = result.current.checkHasRedeemed;
      const initialMarkAsRedeemed = result.current.markAsRedeemed;

      rerender();

      expect(result.current.checkHasRedeemed).toBe(initialCheckHasRedeemed);
      expect(result.current.markAsRedeemed).toBe(initialMarkAsRedeemed);
    });

    it('should update function when accountId changes', () => {
      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: null,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      const { result, rerender } = renderHook(() => usePermission());

      const initialCheckHasRedeemed = result.current.checkHasRedeemed;
      const initialMarkAsRedeemed = result.current.markAsRedeemed;

      (getClientNRC as jest.Mock).mockReturnValue('87654321');

      rerender();

      expect(result.current.checkHasRedeemed).not.toBe(initialCheckHasRedeemed);
      expect(result.current.markAsRedeemed).not.toBe(initialMarkAsRedeemed);
    });

    it('should update checkHasRedeemed when hasRedeemed changes', () => {
      let currentHasRedeemed = null;

      mockUseRootStore.mockImplementation((selector: any) => {
        if (typeof selector === 'function') {
          return selector({
            rewardsPermission: {
              hasRedeemed: currentHasRedeemed,
              status: PermissionStatus.IDLE,
            },
          });
        }
      });

      const { result, rerender } = renderHook(() => usePermission());

      const initialCheckHasRedeemed = result.current.checkHasRedeemed;

      currentHasRedeemed = true;
      rerender();

      expect(result.current.checkHasRedeemed).not.toBe(initialCheckHasRedeemed);
    });
  });
});

