import { eventSelectContent } from '../../../../src/constants/functions';
import { usePhysicalCards, useVirtualCardNumber } from '../../../../src/hooks/useSelectors';
import {
  createFunctionalityCarrousel,
  getInvoiceToDisplay,
} from '../../../../src/screens/FintechHome/data';
import { useCarrouselItems } from '../../../../src/hooks/custom/useCarrouselItems';
import { InvoiceFintechItem } from '../../../../src/redux/ducks/invoices';
import { render } from '@testing-library/react-native';
import { renderHook } from '@testing-library/react-hooks';
import { render } from '@testing-library/react-native';
import { TestProvider } from '../../../__mocks__/utils/test-provider';
import React from 'react';

jest.mock('../../../../src/hooks/useSelectors', () => ({
  usePhysicalCards: jest.fn(),
  useVirtualCardNumber: jest.fn(),
}));

jest.mock('~/constants/functions', () => ({
  eventSelectContent: jest.fn(),
}));


const mockedNavigate = jest.fn();
const mockedOpen = jest.fn();

const navigation = { navigate: mockedNavigate };

const modalizeRef = {
  current: {
    open: mockedOpen,
  },
};

const modalizeValidateAddressRef = {
  current: {
    open: jest.fn(),
  },
};

const renderFunctionality = (
  initialState = {
    customerReducer: { userKYC: '0' },
  }
) => {
  let result: any;

  const TestComponent = () => {
    result = createFunctionalityCarrousel(
      navigation as any,
      modalizeRef as any,
      modalizeValidateAddressRef as any
    );
    return null;
  };

  render(
    React.createElement(
      TestProvider,
      { initialState },
      React.createElement(TestComponent, null),
    ),
  );

  return result;
};

describe('createFunctionalityCarrousel - cobertura completa', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    (usePhysicalCards as jest.Mock).mockReturnValue([
      { Bloqueio: false, NrCartao: '987654321098' },
    ]);
  });

  it('deve retornar todos os itens esperados com campos definidos e executar todos os onPress', () => {
    const result = renderFunctionality({
      customerReducer: { userKYC: '0' },
    });

    expect(result).toHaveLength(3);
    expect(result[0].icon).toBe('icon-card');
    expect(result[0].title).toMatch(/Bloqueio/i);
    expect(result[0].testID).toBe('btnFintechHomeBlockCard');
    result[0].onPress();

    expect(eventSelectContent).toHaveBeenCalledWith(
      expect.objectContaining({ content_id: 'bloqueio_temporario' })
    );
    expect(mockedOpen).toHaveBeenCalled();

    expect(result[1].icon).toBe('icon-star');
    expect(result[1].title).toMatch(/benefícios/i);
    expect(result[1].testID).toBe('btnFintechHomeMyBenefits');
    result[1].onPress();
    expect(mockedNavigate).toHaveBeenCalledWith('FintechBenefits');

    expect(result[2].icon).toBe('icon-help');
    expect(result[2].title).toMatch(/ajuda/i);
    expect(result[2].testID).toBe('btnFintechHomeHelp');
    result[2].onPress();
    expect(mockedNavigate).toHaveBeenCalledWith('HelpScreen');
  });
  it('deve abrir modal de validação quando userKYC é 1', () => {
    const result = renderFunctionality({
      customerReducer: { userKYC: '1' },
    });

    result[0].onPress();

    expect(modalizeValidateAddressRef.current.open).toHaveBeenCalled();
    expect(eventSelectContent).not.toHaveBeenCalledWith(
      expect.objectContaining({ content_id: 'bloqueio_temporario' })
    );
  });
});

describe('createCarrouselItems - cobertura de retorno + estrutura de cada item', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('deve retornar todos os campos preenchidos com onPress funcional e disparar navegação e evento', () => {
    (usePhysicalCards as jest.Mock).mockReturnValue([
      { Bloqueio: false, NrCartao: '987654321098' },
    ]);
    (useVirtualCardNumber as jest.Mock).mockReturnValue('1234567890123456');

    const { result } = renderHook(
      () =>
        useCarrouselItems({
          navigation: navigation as any,
          modalizeRef: modalizeRef as any,
          modalizeValidateAddressRef: modalizeValidateAddressRef as any,
        }),
      {
        wrapper: ({ children }: { children: React.ReactNode }) =>
          React.createElement(
            TestProvider as any,
            {
              initialState: {
                customerReducer: { userKYC: '0' },
                featuresReducer: {
                  rewardProgram: true,
                },
                customerReducer: { userKYC: '0' },
              },
            },
            children
          ),
      }
    );

    const items = result.current;

    expect(items).toHaveLength(4);

    for (const item of items) {
      expect(item.icon).toBeDefined();
      expect(item.name).toBeDefined();
      expect(typeof item.onPress).toBe('function');
    }

    for (const item of items) {
      item?.onPress?.();
    }

    expect(mockedNavigate).toHaveBeenCalledWith(
      'DetailVirtualCardRecurrent',
      expect.objectContaining({ analytics: expect.any(Object) })
    );

    expect(mockedNavigate).toHaveBeenCalledWith(
      'AdditionalCardInstructions',
      expect.objectContaining({ analytics: expect.any(Object) })
    );

    expect(mockedNavigate).toHaveBeenCalledWith(
      'RewardProgram',
      expect.objectContaining({ analytics: expect.any(Object) })
    );

    expect(eventSelectContent).toHaveBeenCalledTimes(4);
  });
});

describe('getInvoiceToDisplay', () => {
  const baseInvoice = {
    Pagamento: 'Não Pago',
    Valor: 100,
    ValorPago: 0,
    ValorPgtoMinimo: 0,
    ParcelamentoDisponivel: false,
  };

  const daysAgo = (d: number) => {
    const date = new Date();
    date.setDate(date.getDate() - d);
    return date.toISOString();
  };
  const daysAhead = (d: number) => {
    const date = new Date();
    date.setDate(date.getDate() + d);
    return date.toISOString();
  };

  it('returns overdue invoice first', () => {
    const invoices: InvoiceFintechItem[] = [
      {
        ...baseInvoice,
        Situacao: 'default',
        Status: 'Fechada',
        Fechamento: daysAgo(10),
        Vencimento: daysAgo(7), // vencida há 7 dias
      } as unknown as InvoiceFintechItem,
    ];
    const selected = getInvoiceToDisplay(invoices);
    expect(selected).toBe(invoices[0]);
  });

  it('returns closed and unpaid invoice if no overdue', () => {
    const invoices: InvoiceFintechItem[] = [
      {
        ...baseInvoice,
        Situacao: 'default',
        Status: 'Fechada',
        Fechamento: daysAgo(5),
        Vencimento: daysAhead(3),
      } as unknown as InvoiceFintechItem,
    ];
    const selected = getInvoiceToDisplay(invoices);
    expect(selected).toBe(invoices[0]);
  });

  it('returns open invoice if no overdue or closed unpaid', () => {
    const invoices: InvoiceFintechItem[] = [
      {
        ...baseInvoice,
        Situacao: 'default',
        Status: 'Em Aberto',
        Fechamento: daysAgo(2),
        Vencimento: daysAhead(5),
      } as unknown as InvoiceFintechItem,
    ];
    const selected = getInvoiceToDisplay(invoices);
    expect(selected).toBe(invoices[0]);
  });

  it('returns last filtered if no matching status', () => {
    const invoices: InvoiceFintechItem[] = [
      {
        ...baseInvoice,
        Situacao: 'default',
        Status: 'OutroStatus',
        Fechamento: daysAgo(1),
        Vencimento: daysAhead(10),
      } as unknown as InvoiceFintechItem,
    ];
    const selected = getInvoiceToDisplay(invoices);
    expect(selected).toBe(invoices[0]);
  });

  it('returns most recent unidentifiedPayment if nothing else', () => {
    const invoices: InvoiceFintechItem[] = [
      {
        ...baseInvoice,
        Situacao: 'unidentifiedPayment',
        Status: 'Atrasada',
        Fechamento: daysAgo(5),
        Vencimento: daysAgo(3),
      } as unknown as InvoiceFintechItem,
      {
        ...baseInvoice,
        Situacao: 'unidentifiedPayment',
        Status: 'Atrasada',
        Fechamento: daysAgo(1),
        Vencimento: daysAgo(1),
      } as unknown as InvoiceFintechItem,
    ];
    const selected = getInvoiceToDisplay(invoices);
    expect(selected?.Fechamento).toBe(invoices[1].Fechamento); // mais recente
  });

  it('returns null for empty array', () => {
    expect(getInvoiceToDisplay([])).toBeNull();
  });
});

